void QosScheduler::advanceState(QosEvent ev) {
    switch (ev) {
        case QosEvent::Admit:
            if (m_state == QosState::Idle)
                m_state = QosState::Running;
            break;
        case QosEvent::Throttle:
            if (m_state == QosState::Running)
                m_state = QosState::Paused;
            break;
        case QosEvent::Complete:
            m_state = QosState::Idle;
            break;
    }
}
